**`<Link>`** — Next.js component for internal navigation

```tsx
import Link from 'next/link';

<Link href="/about">About Us</Link>
```

**`<a>`** — Standard HTML anchor for external links

```tsx
<a href="https://google.com" target="_blank" rel="noopener noreferrer">
  Google
</a>
```

---

**Key Differences:**

**1. Navigation Type:**
- `<Link>`: **Client-side** navigation (no page reload)
- `<a>`: **Full page reload** (browser requests new HTML)

**2. Performance:**
```tsx
// ✅ Link - Fast (no reload)
<Link href="/products">Products</Link>
// User clicks → JavaScript updates URL → Component renders → Instant!

// ❌ <a> - Slow (full reload)
<a href="/products">Products</a>
// User clicks → Browser requests /products → Server responds → Parse HTML → Download JS → Render
```

**3. Prefetching:**
```tsx
// ✅ Link automatically prefetches pages in viewport
<Link href="/about">About</Link>
// When link appears on screen, Next.js downloads the page in background
// Click = instant navigation!

// ❌ <a> doesn't prefetch
<a href="/about">About</a>
// Click = wait for download
```

**4. Scroll Preservation:**
```tsx
// ✅ Link preserves scroll position on back navigation
User: /home → /products (scrolls down) → back to /home
// Link remembers scroll position on /home

// ❌ <a> always scrolls to top
```

**5. State Preservation:**
```tsx
// ✅ Link preserves React state during navigation
const [count, setCount] = useState(0);
// Navigate with Link → count persists if component stays mounted

// ❌ <a> causes full reload → all state lost
```

---

**When to use each:**

**Use `<Link>` for:**
✅ Internal pages (`/about`, `/blog`, `/products`)
✅ Better performance
✅ Better user experience

**Use `<a>` for:**
✅ External URLs (`https://google.com`)
✅ Downloads (`/file.pdf`)
✅ Mailto/tel links (`mailto:email@example.com`)

---

**Example:**

```tsx
import Link from 'next/link';

export default function Navigation() {
  return (
    <nav>
      {/* ✅ Internal navigation */}
      <Link href="/">Home</Link>
      <Link href="/about">About</Link>
      <Link href="/blog">Blog</Link>

      {/* ✅ External link */}
      <a href="https://github.com" target="_blank" rel="noopener noreferrer">
        GitHub
      </a>

      {/* ❌ WRONG: Using <a> for internal */}
      <a href="/contact">Contact (causes reload!)</a>
    </nav>
  );
}
```

**Route Handlers** are Next.js's built-in API routes — backend endpoints in your app.

**File:** `app/api/tasks/route.ts`

```tsx
// app/api/tasks/route.ts
import { NextResponse } from 'next/server';

// In-memory store (in production, use a database)
let tasks = [
  { id: 1, title: 'Learn Next.js', completed: false },
  { id: 2, title: 'Build a project', completed: false },
];

let nextId = 3;

// GET /api/tasks - Get all tasks
export async function GET(request) {
  // Optional: Filter by query params
  const { searchParams } = new URL(request.url);
  const completed = searchParams.get('completed');

  let filteredTasks = tasks;

  if (completed !== null) {
    filteredTasks = tasks.filter(t => 
      t.completed === (completed === 'true')
    );
  }

  return NextResponse.json(filteredTasks);
}

// POST /api/tasks - Create a new task
export async function POST(request) {
  try {
    const body = await request.json();

    // Validate
    if (!body.title || body.title.trim() === '') {
      return NextResponse.json(
        { error: 'Title is required' },
        { status: 400 }
      );
    }

    // Create task
    const newTask = {
      id: nextId++,
      title: body.title,
      completed: body.completed || false,
    };

    tasks.push(newTask);

    return NextResponse.json(newTask, { status: 201 });
  } catch (error) {
    return NextResponse.json(
      { error: 'Invalid JSON' },
      { status: 400 }
    );
  }
}

// DELETE /api/tasks?id=1 - Delete a task
export async function DELETE(request) {
  const { searchParams } = new URL(request.url);
  const id = parseInt(searchParams.get('id'));

  if (!id) {
    return NextResponse.json(
      { error: 'Task ID is required' },
      { status: 400 }
    );
  }

  const index = tasks.findIndex(t => t.id === id);

  if (index === -1) {
    return NextResponse.json(
      { error: 'Task not found' },
      { status: 404 }
    );
  }

  tasks.splice(index, 1);

  return NextResponse.json({ success: true });
}
```

