// app/api/tasks/[id]/route.ts
import { NextResponse } from 'next/server';
import { tasks } from '../route';  // Import shared data

// GET /api/tasks/1 - Get single task
export async function GET(request, { params }) {
  const id = parseInt(params.id);
  const task = tasks.find(t => t.id === id);

  if (!task) {
    return NextResponse.json(
      { error: 'Task not found' },
      { status: 404 }
    );
  }

  return NextResponse.json(task);
}

// PATCH /api/tasks/1 - Update task
export async function PATCH(request, { params }) {
  const id = parseInt(params.id);
  const task = tasks.find(t => t.id === id);

  if (!task) {
    return NextResponse.json(
      { error: 'Task not found' },
      { status: 404 }
    );
  }

  const body = await request.json();

  // Update fields
  if (body.title !== undefined) task.title = body.title;
  if (body.completed !== undefined) task.completed = body.completed;

  return NextResponse.json(task);
}

// DELETE /api/tasks/1 - Delete task (alternative to query param)
export async function DELETE(request, { params }) {
  const id = parseInt(params.id);
  const index = tasks.findIndex(t => t.id === id);

  if (index === -1) {
    return NextResponse.json(
      { error: 'Task not found' },
      { status: 404 }
    );
  }

  const deleted = tasks.splice(index, 1)[0];
  return NextResponse.json(deleted);
}
