**Server Actions** are asynchronous functions that run on the server. They're the modern way to handle forms in Next.js — no API routes needed!

**Benefits:**
- ✅ No separate API route needed
- ✅ Progressive enhancement (works without JS)
- ✅ Type-safe
- ✅ Automatic revalidation

---

**Server Action with Validation:**

```tsx
// app/actions/posts.ts
'use server';

import { revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';
import { z } from 'zod';
import { prisma } from '@/lib/prisma';

// Validation schema
const PostSchema = z.object({
  title: z.string().min(3, 'Title must be at least 3 characters').max(100),
  content: z.string().min(10, 'Content must be at least 10 characters'),
  category: z.enum(['tutorial', 'guide', 'news']),
  published: z.boolean().default(false),
});

export async function createPost(formData) {
  // Extract form data
  const data = {
    title: formData.get('title'),
    content: formData.get('content'),
    category: formData.get('category'),
    published: formData.get('published') === 'on',
  };

  // Validate
  const result = PostSchema.safeParse(data);

  if (!result.success) {
    // Return validation errors
    return {
      success: false,
      errors: result.error.flatten().fieldErrors,
    };
  }

  // Create post in database
  try {
    const post = await prisma.post.create({
      data: {
        ...result.data,
        slug: result.data.title.toLowerCase().replace(/\s+/g, '-'),
      },
    });

    // Revalidate blog page
    revalidatePath('/blog');

    // Redirect to new post
    redirect(`/blog/${post.slug}`);
  } catch (error) {
    return {
      success: false,
      errors: { _form: ['Failed to create post'] },
    };
  }
}
```

