**Advanced Example with Session Verification:**

```tsx
// middleware.ts
import { NextResponse } from 'next/server';
import { verifySession } from './lib/auth';

export async function middleware(request) {
  const sessionToken = request.cookies.get('session')?.value;
  const { pathname } = request.nextUrl;

  // Protected routes
  const protectedRoutes = ['/dashboard', '/profile', '/settings', '/admin'];
  const isProtected = protectedRoutes.some(route => 
    pathname.startsWith(route)
  );

  if (isProtected) {
    // No session token
    if (!sessionToken) {
      const loginUrl = new URL('/login', request.url);
      loginUrl.searchParams.set('from', pathname);
      return NextResponse.redirect(loginUrl);
    }

    // Verify session (check if valid and not expired)
    const session = await verifySession(sessionToken);

    if (!session) {
      // Invalid/expired session
      const response = NextResponse.redirect(new URL('/login', request.url));
      response.cookies.delete('session');  // Clear invalid cookie
      return response;
    }

    // Admin-only routes
    if (pathname.startsWith('/admin') && session.user.role !== 'admin') {
      return NextResponse.redirect(new URL('/dashboard', request.url));
    }

    // Add user info to request headers (accessible in pages)
    const response = NextResponse.next();
    response.headers.set('x-user-id', session.user.id);
    response.headers.set('x-user-role', session.user.role);
    return response;
  }

  // Redirect logged-in users away from auth pages
  if (['/login', '/register'].includes(pathname) && sessionToken) {
    return NextResponse.redirect(new URL('/dashboard', request.url));
  }

  return NextResponse.next();
}

export const config = {
  matcher: [
    '/dashboard/:path*',
    '/profile/:path*',
    '/settings/:path*',
    '/admin/:path*',
    '/login',
    '/register',
  ],
};
```

