**7. Middleware:**

```tsx
// middleware.ts
import { NextResponse } from 'next/server';

export function middleware(request) {
  const sessionCookie = request.cookies.get('session');
  const { pathname } = request.nextUrl;

  const isProtected = pathname.startsWith('/dashboard');
  const isAuthPage = ['/login', '/register'].includes(pathname);

  // Redirect to login if accessing protected route without session
  if (isProtected && !sessionCookie) {
    return NextResponse.redirect(new URL('/login', request.url));
  }

  // Redirect to dashboard if already logged in and trying to access auth pages
  if (isAuthPage && sessionCookie) {
    return NextResponse.redirect(new URL('/dashboard', request.url));
  }

  return NextResponse.next();
}

export const config = {
  matcher: ['/dashboard/:path*', '/login', '/register'],
};
```

---

**Flow:**

1. User visits `/dashboard` → No session → Redirected to `/login`
2. User fills login form → Submits → Server Action validates
3. Valid credentials → Creates session → Sets cookie → Redirects to `/dashboard`
4. User sees dashboard with their info
5. User clicks logout → Deletes session → Clears cookie → Redirects to home

✅ Secure (passwords hashed, httpOnly cookies)
✅ Simple (no JWT complexity)
✅ Fast (session lookup)
✅ Protected routes
✅ Redirect after login
